mapper.select:
SELECT VENDOR_ID AS vendorId, VENDOR_NAME AS vendorName, VENDOR_TYPE AS vendorType, VENDOR_TEL AS vendorTel, VENDOR_EMAIL AS vendorEmail, VENDOR_ADDRESS AS vendorAddress, VENDOR_USAGE AS vendorUsage FROM VENDOR
AND VENDOR_NAME LIKE '%' || #{vendorName} || '%'
AND VENDOR_TYPE = #{vendorType}
AND VENDOR_USAGE = #{vendorUsage}
ORDER BY VENDOR_ID DESC
